import { useState, useEffect, useRef } from "react";
import { useAuth } from "../context/AuthContext";
import API from "../services/api";
import socket from "../services/socket";
import Sidebar from "../components/Sidebar";
import ChatWindow from "../components/ChatWindow";
import StatusBar from "../components/StatusBar";
import ProfileModal from "../components/ProfileModal";
import UserProfileModal from "../components/UserProfileModal";
import "./Chat.css";

export default function Chat() {
  const { user, logout, updateUser } = useAuth();
  const [friends, setFriends] = useState([]);
  const [selectedFriend, setSelectedFriend] = useState(null);
  const [messages, setMessages] = useState([]);
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [typingUser, setTypingUser] = useState(null);
  const [text, setText] = useState("");
  const [showMyProfile, setShowMyProfile] = useState(false);
  const [showUserProfile, setShowUserProfile] = useState(false);
  const [canMsg, setCanMsg] = useState({ canMessage: true, mutualFollow: false, msgCount: 0 });
  const [msgError, setMsgError] = useState("");
  const [mediaPreview, setMediaPreview] = useState(null);
  const [uploading, setUploading] = useState(false);
  const typingTimer = useRef(null);
  const selectedFriendRef = useRef(selectedFriend);
  const mediaRef = useRef();

  useEffect(() => { selectedFriendRef.current = selectedFriend; }, [selectedFriend]);

  useEffect(() => {
    socket.connect();
    socket.emit("userOnline", user.username);
    socket.on("onlineUsers", setOnlineUsers);

    socket.on("receiveMessage", (msg) => {
      const sf = selectedFriendRef.current;
      if (sf && (msg.sender === sf.username || msg.receiver === sf.username)) {
        setMessages(prev => [...prev, msg]);
        socket.emit("messageSeen", msg._id);
      }
    });

    socket.on("messageSent", (msg) => {
      setMessages(prev => [...prev, msg]);
    });

    socket.on("messageStatus", ({ messageId, status }) => {
      setMessages(prev => prev.map(m => m._id === messageId ? { ...m, status } : m));
    });

    socket.on("allMessagesSeen", ({ from }) => {
      const sf = selectedFriendRef.current;
      if (sf && sf.username === from) {
        setMessages(prev => prev.map(m => ({ ...m, status: "seen" })));
      }
    });

    socket.on("typing", (sender) => {
      if (selectedFriendRef.current?.username === sender) setTypingUser(sender);
    });

    socket.on("stopTyping", () => setTypingUser(null));

    socket.on("messageError", ({ message }) => {
      setMsgError(message);
      setTimeout(() => setMsgError(""), 4000);
    });

    return () => {
      socket.off("onlineUsers"); socket.off("receiveMessage");
      socket.off("messageSent"); socket.off("messageStatus");
      socket.off("allMessagesSeen"); socket.off("typing");
      socket.off("stopTyping"); socket.off("messageError");
      socket.disconnect();
    };
  }, []);

  useEffect(() => {
    API.get("/users").then(res => setFriends(res.data)).catch(console.log);
  }, []);

  useEffect(() => {
    if (!selectedFriend) return;
    API.get(`/messages/${selectedFriend.username}`)
      .then(res => {
        setMessages(res.data);
        socket.emit("markAllSeen", { sender: selectedFriend.username, receiver: user.username });
      }).catch(console.log);

    // Check messaging permission
    API.get(`/messages/${selectedFriend.username}/can`)
      .then(res => setCanMsg(res.data))
      .catch(console.log);
  }, [selectedFriend]);

  const handleSend = () => {
    if ((!text.trim() && !mediaPreview) || !selectedFriend) return;
    if (!canMsg.canMessage) {
      setMsgError("You can only send 1 message until they follow you back");
      return;
    }
    socket.emit("sendMessage", {
      sender: user.username,
      receiver: selectedFriend.username,
      text: text.trim(),
      mediaUrl: mediaPreview?.url || "",
      mediaType: mediaPreview?.type || "",
    });
    setText("");
    setMediaPreview(null);
    socket.emit("stopTyping", { receiver: selectedFriend.username });
  };

  const handleKey = (e) => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSend(); }
  };

  const handleTyping = () => {
    socket.emit("typing", { receiver: selectedFriend?.username, sender: user.username });
    clearTimeout(typingTimer.current);
    typingTimer.current = setTimeout(() => {
      socket.emit("stopTyping", { receiver: selectedFriend?.username });
    }, 1500);
  };

  const handleMediaSelect = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setUploading(true);
    const fd = new FormData();
    fd.append("media", file);
    try {
      const res = await API.post("/users/me/media", fd);
      setMediaPreview({ url: res.data.mediaUrl, type: res.data.mediaType });
    } catch (err) { console.log(err); }
    setUploading(false);
  };

  const isOnline = user?.settings?.showOnlineStatus !== false && onlineUsers.includes(selectedFriend?.username);

  // Show messaging limit warning
  const isLimited = !canMsg.mutualFollow && canMsg.msgCount >= 1;

  return (
    <div className="chat-page">
      <Sidebar
        currentUser={user}
        friends={friends}
        selectedFriend={selectedFriend}
        onSelectFriend={setSelectedFriend}
        onlineUsers={onlineUsers}
        onLogout={logout}
        onOpenProfile={() => setShowMyProfile(true)}
        messages={messages}
        typingUser={typingUser}
      />

      <div className="chat-main">
        {/* Status bar */}
        <StatusBar currentUser={user} />

        {selectedFriend ? (
          <>
            {/* Header */}
            <div className="chat-header" onClick={() => setShowUserProfile(true)}>
              <div className="chat-header-left">
                <div className="header-avatar">
                  {selectedFriend.profilePic
                    ? <img src={selectedFriend.profilePic} alt="" />
                    : selectedFriend.username[0].toUpperCase()
                  }
                </div>
                <div className="header-info">
                  <span className="header-name">{selectedFriend.username}</span>
                  <span className={`header-status ${isOnline ? "online" : ""}`}>
                    <span className="status-dot-sm" />
                    {typingUser ? "typing..." : isOnline ? "Active now" : "Offline"}
                  </span>
                </div>
              </div>
              <div className="header-actions" onClick={e => e.stopPropagation()}>
                <button className="icon-btn" onClick={() => setShowUserProfile(true)}>👤</button>
              </div>
            </div>

            {/* Messaging limit banner */}
            {isLimited && (
              <div className="msg-limit-banner">
                🔒 You can only send 1 message until <strong>@{selectedFriend.username}</strong> follows you back
              </div>
            )}

            {/* Messages */}
            <ChatWindow
              messages={messages}
              currentUser={user}
              selectedFriend={selectedFriend}
              typingUser={typingUser}
            />

            {/* Media preview */}
            {mediaPreview && (
              <div className="media-preview-bar">
                {mediaPreview.type === "video"
                  ? <video src={mediaPreview.url} className="media-preview-thumb" />
                  : <img src={mediaPreview.url} alt="" className="media-preview-thumb" />
                }
                <button className="media-preview-remove" onClick={() => setMediaPreview(null)}>✕</button>
              </div>
            )}

            {/* Error */}
            {msgError && <div className="msg-error-bar">{msgError}</div>}

            {/* Input */}
            <div className="input-bar">
              <input ref={mediaRef} type="file" accept="image/*,video/*" hidden onChange={handleMediaSelect} />
              <button className="attach-btn" onClick={() => mediaRef.current.click()} disabled={uploading}>
                {uploading ? "⏳" : "📎"}
              </button>
              <textarea
                className="msg-input"
                placeholder={isLimited ? "Follow each other to chat freely..." : `Message @${selectedFriend.username}...`}
                value={text}
                onChange={e => { setText(e.target.value); handleTyping(); }}
                onKeyDown={handleKey}
                rows={1}
                disabled={isLimited && !mediaPreview}
              />
              <button
                className={`send-btn ${(text.trim() || mediaPreview) && !isLimited ? "active" : ""}`}
                onClick={handleSend}
                disabled={(!text.trim() && !mediaPreview) || isLimited}
              >
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2">
                  <line x1="22" y1="2" x2="11" y2="13"/>
                  <polygon points="22 2 15 22 11 13 2 9 22 2"/>
                </svg>
              </button>
            </div>
          </>
        ) : (
          <div className="empty-state">
            <div className="empty-icon">💬</div>
            <h2>Select a conversation</h2>
            <p>Pick someone from the sidebar to start chatting</p>
          </div>
        )}
      </div>

      {showMyProfile && (
        <ProfileModal
          currentUser={user}
          onClose={() => setShowMyProfile(false)}
          onProfileUpdate={updateUser}
        />
      )}

      {showUserProfile && selectedFriend && (
        <UserProfileModal
          targetUsername={selectedFriend.username}
          currentUser={user}
          onClose={() => setShowUserProfile(false)}
        />
      )}
    </div>
  );
}
